import { useRef, useEffect } from 'react'
import { TransformWrapper, TransformComponent, ReactZoomPanPinchRef } from 'react-zoom-pan-pinch'
import { Center, Loader } from '@mantine/core'
import { usePageLoader } from '../hooks/usePageLoader'

const DETAIL_WIDTH = 1400

interface Props {
  pdfPath: string
  pageNum: number
  pageCount: number
  rotation?: number
  onNavigate: (page: number) => void
  onToggleSkip?: () => void
  onRotate?: () => void
}

export default function DetailPanel({ pdfPath, pageNum, pageCount, rotation = 0, onNavigate, onToggleSkip, onRotate }: Props) {
  const { getSrc, isLoading, load } = usePageLoader(pdfPath, DETAIL_WIDTH)
  const transformRef = useRef<ReactZoomPanPinchRef>(null)

  useEffect(() => {
    load(pageNum)
  }, [pdfPath, pageNum])

  useEffect(() => {
    transformRef.current?.resetTransform()
  }, [pageNum, rotation])

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return
      if (e.key === 'ArrowLeft') {
        e.preventDefault()
        if (pageNum > 1) onNavigate(pageNum - 1)
      } else if (e.key === 'ArrowRight') {
        e.preventDefault()
        if (pageNum < pageCount) onNavigate(pageNum + 1)
      } else if (e.key === 'Delete' || e.key === 'Backspace') {
        e.preventDefault()
        onToggleSkip?.()
      } else if (e.key === 'r') {
        e.preventDefault()
        onRotate?.()
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [pageNum, pageCount, onNavigate, onToggleSkip, onRotate])

  const src = getSrc(pageNum)

  return (
    <div
      style={{
        flex: 1,
        height: '100%',
        overflow: 'hidden',
        position: 'relative',
        background: 'var(--mantine-color-gray-1)',
        padding: 8,
      }}
    >
      {isLoading(pageNum) && (
        <Center style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
          <Loader />
        </Center>
      )}
      {src && (
        <TransformWrapper ref={transformRef} centerOnInit minScale={0.1} maxScale={8}>
          <TransformComponent
            wrapperStyle={{ width: '100%', height: '100%' }}
            contentStyle={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <img
              src={src}
              alt={`Page ${pageNum}`}
              draggable={false}
              style={{ maxWidth: '100%', maxHeight: '100%', display: 'block', userSelect: 'none', transform: rotation ? `rotate(${rotation}deg)` : undefined }}
            />
          </TransformComponent>
        </TransformWrapper>
      )}
    </div>
  )
}

import { useState } from 'react'
import { Box, Button } from '@mantine/core'
import ThumbnailPanel from './ThumbnailPanel'
import DetailPanel from '../DetailPanel'
import { OpenPDF, PageCount } from '../../../wailsjs/go/main/App'

export default function SplitMode() {
  const [pdfPath, setPdfPath] = useState<string | null>(null)
  const [pageCount, setPageCount] = useState(0)
  const [selectedPage, setSelectedPage] = useState(1)

  const handleOpen = async () => {
    const path = await OpenPDF()
    if (!path) return
    const count = await PageCount(path)
    setPdfPath(path)
    setPageCount(count)
    setSelectedPage(1)
  }

  return (
    <Box style={{ display: 'flex', height: '100%' }}>
      {pdfPath ? (
        <>
          <ThumbnailPanel
            pdfPath={pdfPath}
            pageCount={pageCount}
            selectedPage={selectedPage}
            onSelectPage={setSelectedPage}
          />
          <DetailPanel
            pdfPath={pdfPath}
            pageNum={selectedPage}
            pageCount={pageCount}
            onNavigate={setSelectedPage}
          />
        </>
      ) : (
        <Box style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Button onClick={handleOpen}>Open PDF</Button>
        </Box>
      )}
    </Box>
  )
}

import { useState } from 'react'
import { OpenPDF, PageCount } from '../../wailsjs/go/main/App'

export interface PDFFile {
  path: string | null
  count: number
  skipped: Set<number>
  rotations: Map<number, number>
  load: () => Promise<boolean>
  toggleSkip: (page: number) => void
  rotate: (page: number) => void
}

export function usePDFFile(): PDFFile {
  const [path, setPath] = useState<string | null>(null)
  const [count, setCount] = useState(0)
  const [skipped, setSkipped] = useState<Set<number>>(() => new Set())
  const [rotations, setRotations] = useState<Map<number, number>>(() => new Map())

  const load = async () => {
    const p = await OpenPDF()
    if (!p) return false
    const c = await PageCount(p)
    setPath(p)
    setCount(c)
    setSkipped(new Set())
    setRotations(new Map())
    return true
  }

  const toggleSkip = (page: number) => {
    setSkipped(prev => {
      const next = new Set(prev)
      if (next.has(page)) next.delete(page); else next.add(page)
      return next
    })
  }

  const rotate = (page: number) => {
    setRotations(prev => {
      const next = new Map(prev)
      const deg = ((next.get(page) ?? 0) + 90) % 360
      if (deg === 0) next.delete(page); else next.set(page, deg)
      return next
