import { useRef, useState, useEffect } from 'react'
import { RenderPage } from '../../wailsjs/go/main/App'

export interface PageLoader {
  getSrc: (page: number, width: number) => string | undefined
  isLoading: (page: number, width: number) => boolean
  isFailed: (page: number, width: number) => boolean
  load: (page: number, width: number) => void
  invalidate: () => void
}

export function usePageLoader(pdfPath: string): PageLoader {
  const cacheRef = useRef(new Map<string, string>())
  const loadingRef = useRef(new Set<string>())
  const failedRef = useRef(new Set<string>())
  const [, setTick] = useState(0)

  const cacheKey = (page: number, width: number) => `${page}:${width}`

  const invalidate = () => {
    cacheRef.current.clear()
    loadingRef.current.clear()
    failedRef.current.clear()
    setTick(t => t + 1)
  }

  useEffect(() => {
    invalidate()
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pdfPath])

  const load = (page: number, width: number) => {
    const k = cacheKey(page, width)
    if (cacheRef.current.has(k) || loadingRef.current.has(k) || failedRef.current.has(k)) return
    loadingRef.current.add(k)
    RenderPage(pdfPath, page, Math.round(width * window.devicePixelRatio))
      .then((b64: string) => {
        cacheRef.current.set(k, `data:image/png;base64,${b64}`)
        loadingRef.current.delete(k)
        setTick(t => t + 1)
      })
      .catch((err: unknown) => {
        console.error(`RenderPage failed for page ${page}:`, err)
        loadingRef.current.delete(k)
        failedRef.current.add(k)
        setTick(t => t + 1)
      })
  }

  return {
    getSrc: (page, width) => cacheRef.current.get(cacheKey(page, width)),
    isLoading: (page, width) => loadingRef.current.has(cacheKey(page, width)),
    isFailed: (page, width) => failedRef.current.has(cacheKey(page, width)),
    load,
    invalidate,
  }
}

