                      height: LABEL_HEIGHT,
                      lineHeight: `${LABEL_HEIGHT}px`,
                    }}
                  >
                    {pageNumberLabel ? pageNumberLabel(item.index) : page}
                  </div>
                </div>
              )
            })}
          </div>
        </div>
      </div>

      {/* Resize drag handle */}
      {!hideDragHandle && (
        <div
          onMouseDown={startDrag}
